import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as p,o,c as n,a as r,b as e,d as m,e as i}from"./app-706bfe03.js";const s={},h=i('<h1 id="webkit架构和模块" tabindex="-1"><a class="header-anchor" href="#webkit架构和模块" aria-hidden="true">#</a> webkit架构和模块</h1><h2 id="webkit架构及模块" tabindex="-1"><a class="header-anchor" href="#webkit架构及模块" aria-hidden="true">#</a> webkit架构及模块</h2><h3 id="获取webkit" tabindex="-1"><a class="header-anchor" href="#获取webkit" aria-hidden="true">#</a> 获取webkit</h3>',3),d={href:"https://webkit.org/",target:"_blank",rel:"noopener noreferrer"},b=i('<h3 id="webkit架构" tabindex="-1"><a class="header-anchor" href="#webkit架构" aria-hidden="true">#</a> webkit架构</h3><p>webkit的一个显著特征就是它支持不同的浏览器。因为不同浏览器需求不同，所以在webkit中，一些代码可以共享，但另一部分是不同的，不同的部分称为webkit的移植（Ports）。</p><p>在第1章曾介绍过一张简单的webkit结构图：</p><p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1guvmchqsy2j60al03taa402.jpg" alt=""></p><p>本节重点介绍webkit架构的细节，如下图：</p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1guxwqgwba5j60ni0bejtz02.jpg" style="zoom:85%;"><p>图中虚线框表示该模块在不同浏览器使用的webkit内核中的实现是不一样的。实线框标记的模块（WebCore）表示它们基本上是共享的。</p><p>下面主要介绍webkit项目中的 <em>WebCore</em>、<em>JavaScriptCore</em>、<em>WebkitPorts</em>。</p><ul><li><p>WebCore</p><p>WebCore部分包含了目前被各个浏览器所使用的webkit共享部分，这些都是加载和渲染网页的基础模块，它们必不可少。</p><p>具体包括HTML解释器、CSS解释器、SVG、DOM、渲染树（RenderObject树、RenderLayer树等），以及Inspector（Web Inspector、调试网页）。</p></li><li><p>JavaScriptCore</p><p>JavaScriptCore 引擎是 webkit 中的默认 JavaScript 引擎。</p><p>事实上，webkit 中对 JavaScript 引擎的调用是独立于引擎的。因此，它是可替换的。在 Chromium 中，JavaScriptCore 引擎被替换成 V8 引擎。</p></li><li><p>WebkitPorts</p><p>Webkit Ports 指的是 webkit 中的非共享部分。</p><p>对于不同浏览器来说，移植中的这些模块由于平台差异、需求不同等各种原因，往往自己设计实现，这是导致众多 webkit 版本的行为不一致的重要原因。</p></li></ul><p>WebCore 和 Webkit Ports 之上的层主要是提供嵌入式编成接口，这些接口是提供给浏览器调用的。因为接口与具体的移植有关，所以有一个与浏览器相关的绑定层。绑定层之上就是 webkit 项目对外暴露的接口层。</p><p>webkit 还有一个部分在图中没有展现出来，那就是测试用例，包括布局测试用例（<em>Layout Tests</em>）和性能测试用例（<em>Performance Tests</em>），这两类测试包含了大量的测试用例和期望结果。</p><p>为了保证 webkit 的代码质量，这些用例被用来验证渲染结果的正确性。每个浏览器所用的 webkit 必须保证能够编译出来一个可执行程序，称为 <em>DumoRenderTree</em>，它被用来运行测试用例并将渲染结果和期望对比。</p><h3 id="webkit源代码结构" tabindex="-1"><a class="header-anchor" href="#webkit源代码结构" aria-hidden="true">#</a> webkit源代码结构</h3><p>webkit 的代码规模相当庞大，幸运的是，它的目录结构非常清晰，通过目录结构基本可以了解webkit的功能模块。</p><p>在一级目录中，重要的目录有 <em>LayoutTest</em>、<em>PerformanceTests</em>、<em>Source</em>、<em>Tools</em>。</p><p>这其中 <em>Source</em> 目录最重要，它包括了后面章节我们要分析的几乎所有部分。</p><p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1guyojj7z2zj60c30dkwfh02.jpg" alt=""></p><p>在 <em>Source</em> 目录中，重要的目录有 <em>JavaScriptCore</em>、<em>WebCore</em>、<em>WebKit</em>，其中 <em>WebCore</em> 尤为重要。</p><p><em>WebCore</em> 中包含HTML解释器、CSS解释器、DOM、资源加载、<em>Web Inspector</em>等模块的代码。</p><p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1guyojni9uej60b10erjsa02.jpg" alt=""></p><h2 id="基于blink的chromium浏览器结构" tabindex="-1"><a class="header-anchor" href="#基于blink的chromium浏览器结构" aria-hidden="true">#</a> 基于Blink的Chromium浏览器结构</h2><p>Chromium 是基于 webkit(Blink) 的，通过 Chromium 可以了解“如何基于 webkit 构建浏览器”。</p><p>Chromium 是很多新技术的创建者，它将很多先进的理念引入到浏览器领域。Chromium 的代码非常复杂，模块非常多，且结构不太清晰。</p><p>为了方便理解，下面从架构模块、多进程模型、多线程模型等角度解析。</p><h3 id="架构和模块" tabindex="-1"><a class="header-anchor" href="#架构和模块" aria-hidden="true">#</a> 架构和模块</h3><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1guyojqw7kcj60eo09jq3d02.jpg" style="zoom:85%;"><p>在整个 Chromium 中，Blink 只是其中一块，和它并列的还有众多模块，比如 <em>GPU / CommandBuffer</em> （硬件加速架构）、<em>V8 JavaScript</em> 引擎等。</p><p>在这些模块之上的是著名的 “Content 模块” 和 “Content API”，它们是 Chromium 对渲染网页功能的抽象。</p><p>“Content” 的本意是指网页的内容，这里指用来渲染网页内容的模块。</p><p>没有 Content 模块，开发者也可以在 webkit 上渲染网页，但是没有办法获得沙箱模型、跨进程的 GPU 硬件加速机制、HTML5 功能，因为这些功能都是在 Content 层里实现的。</p><p>“Content 模块” 和 “Content API” 将下层的渲染机制、安全机制等隐藏起来，提供一个接口层。</p><p>该接口被上层模块调用，内部调用者包括 Chromium 浏览器、<em>Content Shell</em> 等；外层调用者有 <em>CEF(Chromium Embedded Framework)</em>、Opera 浏览器等。</p><h3 id="多进程模型" tabindex="-1"><a class="header-anchor" href="#多进程模型" aria-hidden="true">#</a> 多进程模型</h3><p>现代浏览器大都支持多线程模型，虽然多线程模型不可避免地带来一些问题，比如更多的资源消耗和复杂的实现，但是它至少带来三点好处：</p><ul><li>避免单个页面的不响应或崩溃而影响整个浏览器</li><li>第三方插件崩溃时不影响页面或浏览器</li><li>方便安全模型的实施，沙箱模型是基于多进程架构的</li></ul><p>下图给出了最常用的 Chromium 浏览器多进程模型。</p><p><em>（由于 Chromium 架构设计的灵活性，使用者可以通过简单的设置来随意改变进程模型）</em></p><p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1guyt91rwppj60cv078dg502.jpg" alt=""></p><p><em>图中方框代表进程，连线代表 IPC 进程间通信。</em></p><p>可以看出，Chromium 主要包括以下几种进程类型：</p><ul><li><p><strong>Browser 进程</strong></p><p>浏览器的主进程，负责浏览器界面的显示、各个页面的管理，是所有其他进程的祖先，负责创建和销毁它们。</p><p><strong>Browser 进程有且只有一个</strong>。</p></li><li><p><strong>Renderer 进程</strong></p><p>网页的渲染进程，负责页面渲染工作，Blink / webkit 的渲染工作主要在这个进程中完成。</p><p><strong>Renderer 进程可能有多个</strong>，但是 Renderer 进程的数量不一定等于打开的页面数量，Chromium 设计了灵活的机制，允许用户配置（后面介绍）。</p></li><li><p><strong>GPU 进程</strong></p><p><strong>最多只有一个</strong>，仅当 GPU 硬件加速打开时才会被创建，主要用于对 3D 图形加速调用的实现。</p></li><li><p>NPAPI、Pepper 插件进程</p><p>为 NPAPI 或 Pepper 类型插件而创建。基本原则是每种类型的插件只会被创建一次，且仅在使用时被创建。</p></li></ul><p>总结一下，桌面系统中的 Chromium 的进程模型有以下特征：</p><ul><li>Browser 进程和页面的渲染是分开的，这保证了页面的崩溃不会导致浏览器页面崩溃</li><li>每个网页是独立的进程，这保证了页面之间相互不影响</li><li>GPU 硬件加速进程、插件进程都是独立的</li></ul><p>上面提到 Chromium 允许用户配置 Renderer 进程被创建的方式，下面简单介绍：</p><ul><li><em>Process-per-site-instance</em>：每个页面都创建一个独立的 Render 进程，不管页面是否来自同一域。</li><li><em>Process-per-site</em>：属于同一个域的页面共享一个进程，不同域则分属不同进程</li><li><em>Process-per-tab</em>：为每个标签页都创建一个独立的进程，不管是否同域或同实例（Chromium 的默认选项，虽然有资源浪费）</li><li><em>Single Process</em>：不为页面创建任何独立的进程，所有的渲染工作都在 Browser 进程中进行，它们是 Browser 进程中的多个线程（不推荐使用）</li></ul><h3 id="browser进程和renderer进程" tabindex="-1"><a class="header-anchor" href="#browser进程和renderer进程" aria-hidden="true">#</a> Browser进程和Renderer进程</h3><p>由于 Browser 进程和 Renderer 进程都是在 webkit 的接口之上由 Chromium 引入的，这里介绍一下他们是如何利用 webkit 渲染网页的。它们的关系如下图所示：</p><p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1guz0rma3k6j60d608n0t802.jpg" alt=""></p><ul><li><p>webkit 接口层：一般基于 webkit 接口层的浏览器直接在上面构建，没有复杂的多进程架构。</p></li><li><p>webkit 黏附层：由于 Chromium 中一些类型和 webkit 内部不一致，所以需要一个简单的桥接层。</p></li><li><p>Renderer：主要处理进程间通信。接受 Browser 进程的请求，调用相应的 webkit 接口，将 webkit 的结果返回。</p></li><li><p>RendererHost：处理与 Renderer 进程之间的通信。给 Renderer 进程发送请求并接收结果。</p></li></ul><p>Browser、Renderer 进程间的关系如上所述，那么，进程内部是如何在支持进程间通信的同时又能支持高校渲染或用户事件响应的？答案是多线程模型。</p><h3 id="多线程模型" tabindex="-1"><a class="header-anchor" href="#多线程模型" aria-hidden="true">#</a> 多线程模型</h3><p>多线程的主要目的是保持用户界面的高响应度，保证 UI 线程（Browser 进程的主线程）不会被任何其他费时的操作阻碍从而影响对用户操作的响应。比如文件读写、socket 读写、数据库操作等。</p><p>在 Renderer 进程中，Chromium 则不让其他操作阻止渲染线程的快速执行。</p><p>更有甚者，为了利用多核的优势，Chromium 将渲染过程管线化，这样可以让渲染的不同阶段在不同的线程执行。</p><p>下图展示了主要进程中的重要线程（这里只列举其中两个）之间的关系：</p><p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1guz2118eotj60cg07daae02.jpg" alt=""></p><p>根据上图，网页的加载和渲染过程的步骤如下：</p><ol><li>Browser 进程收到用户请求，先由 UI 线程处理，后将任务转给 IO，IO 再传递给 Renderer</li><li>Renderer 的 IO 经过简单解释后交给渲染线程。渲染线程接受请求，加载并渲染网页，这可能需要 Browser 获取资源和需要 GPU 进程帮助渲染。最后，Renderer 将结果经 IO 传递给 Browser</li><li>最后，Browser 接收结果并绘制出图像</li></ol><h3 id="content-api" tabindex="-1"><a class="header-anchor" href="#content-api" aria-hidden="true">#</a> Content API</h3><p>顾名思义，<em>Content API</em> 就是一组接口，它屏蔽了底层GPU 硬件加速、多进程、沙箱机制等功能的具体实现，让 <em>Content API</em> 的使用者不需要很多工作即可得到强大的能力。</p><p><em>Content API</em> 的相关定义文件在 Chromium 项目的 “content / public” 目录下。</p><p>按照功能分成六个部分：App、Browser、Common、Plugin、Renderer、Utility。</p><h2 id="webkit2" tabindex="-1"><a class="header-anchor" href="#webkit2" aria-hidden="true">#</a> webkit2</h2><h3 id="webkit2架构及模型" tabindex="-1"><a class="header-anchor" href="#webkit2架构及模型" aria-hidden="true">#</a> webkit2架构及模型</h3><h3 id="webkit和webkit2嵌入式接口" tabindex="-1"><a class="header-anchor" href="#webkit和webkit2嵌入式接口" aria-hidden="true">#</a> webkit和webkit2嵌入式接口</h3><h3 id="比较webkit和chromium的多进程模型" tabindex="-1"><a class="header-anchor" href="#比较webkit和chromium的多进程模型" aria-hidden="true">#</a> 比较webkit和Chromium的多进程模型</h3>',66);function c(l,w){const t=p("ExternalLinkIcon");return o(),n("div",null,[h,r("p",null,[e("webkit是一个开源项目，源代码可以从官方网站"),r("a",d,[e("www.webkit.org"),m(t)]),e("下载。")]),b])}const g=a(s,[["render",c],["__file","3. webkit架构和模块.html.vue"]]);export{g as default};
